/*BACKGROUND COLOR*/ 
	.card { background-color: #D1CFCE; }
	#tags-container { background-color: transparent; }
    /*TIMER COUNTDOWN COLOR*/
 	.timer { color: transparent; }
/* CLOZE COLOR */
