.card {
text-align: center;
font-size: 1rem;
height: 100%;
margin: 0px 15px;
flex-grow: 1;
padding-bottom: 1em;
}
.mobile .card { padding-bottom: 5em; }

/* Details For IMAGES */
.mobile .card img {max-width: 100%!important; }
.mobile .card {margin: 0ex .3px;}

#extra img { min-width: 30%; }
