*/

tmpls.afmt:
{{#Image}}
<div id="io-header">{{Header}}</div>
<div id="io-wrapper">
  <div id="io-overlay">{{Answer Mask}}</div>
  <div id="io-original">{{Image}}</div>
</div>
{{#Footer}}<div id="io-footer">{{Footer}}</div>{{/Footer}}
<button id="io-revl-btn" onclick="toggle();">Toggle Masks</button>
<div id="io-extra-wrapper">
  <div id="io-extra">
    {{#Remarks}}
      <div class="io-extra-entry">
        <div class="io-field-descr">Remarks</div>{{Remarks}}
      </div>
    {{/Remarks}}
    {{#Sources}}
      <div class="io-extra-entry">
        <div class="io-field-descr">Sources</div>{{Sources}}
      </div>
    {{/Sources}}
    {{#Extra 1}}
      <div class="io-extra-entry">
        <div class="io-field-descr">Extra 1</div>{{Extra 1}}
      </div>
    {{/Extra 1}}
    {{#Extra 2}}
      <div class="io-extra-entry">
        <div class="io-field-descr">Extra 2</div>{{Extra 2}}
      </div>
    {{/Extra 2}}
  </div>
</div>

<script>
// Toggle answer mask on clicking the image
var toggle = function() {
  var amask = document.getElementById('io-overlay');
  if (amask.style.display === 'block' || amask.style.display === '')
    amask.style.display = 'none';
  else
    amask.style.display = 'block'
}

// Prevent original image from loading before mask
aFade = 50, qFade = 0;
var mask = document.querySelector('#io-overlay>img');
function loaded() {
    var original = document.querySelector('#io-original');
    original.style.visibility = "visible";
}
if (mask === null || mask.complete) {
    loaded();
} else {
    mask.addEventListener('load', loaded);
}
</script>
{{/Image}}

<!-- BEGIN ANKIHUB MODFICATIONS -->
{{#ankihub_id}}
<a class='ankihub-view-note'
    href='https://app.ankihub.net/decks/notes/{{ankihub_id}}'>
    View Note on AnkiHub
</a>

<style>
.ankihub-view-note {
    display: none;
}

.mobile .ankihub-view-note
  {
    display: block;
    left: 50%;
    margin-right: -50%;
    padding: 8px;
    border-radius: 50px;
    background-color: #cde3f8;
    font-size: 12px;
    color: black;
    text-decoration: none;
}

/* AnkiDroid (Android)
The button is fixed to the bottom of the screen. */
.android .ankihub-view-note {
    position: fixed;
    bottom: 5px;
    transform: translate(-50%, -50%);
}

/* AnkiMobile (IPhone)
position: fixed doesn't work on AnkiMobile, so the button is just below the content instead. */
.iphone .ankihub-view-note,
.ipad .ankihub-view-note {
    position: relative;
    transform: translate(-50%, 0);
    width: fit-content;
    margin-top: 20px;
}
</style>

<script>
    if(document.querySelector("html").classList.contains("android")) {
        // Add a margin to the bottom of the card content so that the button doesn't
        // overlap the content.
        var container = document.querySelector('#qa');
        var button = document.querySelector('.ankihub-view-note');
        container.style.marginBottom = 2 * button.offsetHeight + "px";
    }
</script>

{{/ankihub_id}}
<!-- END ANKIHUB MODFICATIONS -->

<!--
ANKIHUB_END
Text below this comment will not be modified by AnkiHub or AnKing add-ons.
Do not edit or remove this comment if you want to protect the content below.
-->

